import React, { useEffect, useState } from 'react';
import { getAppointments, getPatients, getDoctors, createAppointment } from '../api';
import { Appointment, Patient, Doctor } from '../types';

const AppointmentList: React.FC = () => {
    const [appointments, setAppointments] = useState<Appointment[]>([]);
    const [patients, setPatients] = useState<Patient[]>([]);
    const [doctors, setDoctors] = useState<Doctor[]>([]);
    
    // Siguroha nga ang field names (patient, doctor) motakdo sa imong models.py
    const [formData, setFormData] = useState({ 
        patient: '', 
        doctor: '', 
        appointment_date: '', 
        status: 'Scheduled' 
    });

    const loadData = async () => {
        try {
            const [appRes, patRes, docRes] = await Promise.all([
                getAppointments(), getPatients(), getDoctors()
            ]);
            setAppointments(appRes.data);
            setPatients(patRes.data);
            setDoctors(docRes.data);
        } catch (err) {
            console.error("Error loading data:", err);
        }
    };

    useEffect(() => { loadData(); }, []);

    const handleSchedule = async () => {
        // Validation: Ayaw pasugti kung naay blangko
        if (!formData.patient || !formData.doctor || !formData.appointment_date) {
            alert("Palihog pilia ang Pasyente, Doctor, ug Petsa!");
            return;
        }

        try {
            // Mao ni ang mo-save sa database
            await createAppointment(formData);
            alert("Appointment successfully scheduled!");
            
            // I-reset ang form
            setFormData({ patient: '', doctor: '', appointment_date: '', status: 'Scheduled' });
            loadData(); 
        } catch (err: any) {
            console.error("Error response:", err.response?.data);
            alert("Error! Check if the Doctor and Patient IDs are valid.");
        }
    };

    return (
        <div className="p-6 bg-white rounded shadow-sm border-t-4 border-indigo-600">
            <h2 className="text-xl font-bold mb-4 text-indigo-700">Scheduled Appointments</h2>
            
            <div className="grid grid-cols-1 md:grid-cols-4 gap-2 mb-6 p-4 bg-indigo-50 rounded">
                {/* Patient Selection */}
                <select 
                    value={formData.patient} 
                    onChange={e => setFormData({...formData, patient: e.target.value})} 
                    className="border p-2 rounded"
                    required
                >
                    <option value="">Select Patient</option>
                    {patients.map(p => (
                        <option key={p.patient_id} value={p.patient_id}>
                            {p.last_name}, {p.first_name}
                        </option>
                    ))}
                </select>

                {/* Doctor Selection - Mao ni ang fix sa doctor_id error */}
                <select 
                    value={formData.doctor} 
                    onChange={e => setFormData({...formData, doctor: e.target.value})} 
                    className="border p-2 rounded"
                    required
                >
                    <option value="">Select Doctor</option>
                    {doctors.map(d => (
                        <option key={d.doctor_id} value={d.doctor_id}>
                            Dr. {d.last_name} ({d.specialization})
                        </option>
                    ))}
                </select>

                <input 
                    type="datetime-local" 
                    value={formData.appointment_date} 
                    onChange={e => setFormData({...formData, appointment_date: e.target.value})} 
                    className="border p-2 rounded"
                    required
                />

                <button 
                    onClick={handleSchedule} 
                    className="bg-indigo-600 text-white font-bold px-4 py-2 rounded hover:bg-indigo-700 transition"
                >
                    Schedule
                </button>
            </div>

            <table className="w-full text-left text-sm">
                <thead className="bg-gray-100">
                    <tr>
                        <th className="p-2">ID</th>
                        <th className="p-2">Date & Time</th>
                        <th className="p-2">Status</th>
                    </tr>
                </thead>
                <tbody>
                    {appointments.map(a => (
                        <tr key={a.appointment_id} className="border-b hover:bg-gray-50">
                            <td className="p-2">{a.appointment_id}</td>
                            <td className="p-2">{new Date(a.appointment_date).toLocaleString()}</td>
                            <td className="p-2 font-semibold text-green-600">{a.status}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default AppointmentList;
